import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  "Tình Hình Thế Giới": z.object({
    "Thời Gian": z.string().prefault('Chờ Khởi Tạo'),
    "Đại Thế Thiên Hạ": z.string().prefault('Chờ Khởi Tạo'),
    "Nguy Cơ Hiện Tại": z.string().prefault('Tạm Không'),
    "Uy Tín Chu Thất": z.object({
      "Chỉ Số": z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      "Mô Tả Văn Bản": z.string().prefault('Chờ Khởi Tạo')
    }).prefault({}),
    "Tình Hình Dân Gian": z.string().prefault('Chờ Khởi Tạo'),
    "Động Thái Mỹ Nhân": z.string().prefault('Tạm Không')
  }).prefault({}),

  "Dư Luận Đánh Giá": z.object({
    "Liệt Quốc Đánh Giá": z.record(z.string(), z.object({
      "Đánh Giá Cụ Thể": z.string(),
      "Thái Độ": z.enum(['Thù Địch', 'Đề Phòng', 'Trung Lập', 'Lôi Kéo', 'Kính Sợ'])
    })).prefault({}),
    "Thái Độ Bách Gia": z.record(z.string(), z.object({
      "Đánh Giá Cụ Thể": z.string(),
      "Thái Độ": z.enum(['Thù Địch', 'Bài Xích', 'Trung Lập', 'Tán Thưởng', 'Tôn Sùng'])
    })).prefault({}),
    "Đánh Giá Giai Cấp": z.record(z.string(), z.object({
      "Đánh Giá Cụ Thể": z.string(),
      "Chỉ Số": z.coerce.number().transform(v => _.clamp(v, -100, 100))
    })).prefault({})
  }).prefault({}),

  "Trạng Thái Cá Nhân": z.object({
    "Họ Tên": z.string().prefault('Chờ Khởi Tạo'),
    "Tuổi Tác": z.coerce.number().prefault(15),
    "Biểu Tự": z.string().prefault('Không'),
    "Giai Cấp": z.string().prefault('Chờ Khởi Tạo'),
    "Quan Chức": z.string().prefault('Không'),
    "Trực Thuộc": z.string().prefault('Tạm Không'),
    "Uy Vọng": z.object({
      "Chỉ Số": z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      "Mô Tả Văn Bản": z.string().prefault('Chờ Khởi Tạo')
    }).prefault({}),
    "Thuộc Tính": z.record(
      z.enum(['Phẩm Hạnh', 'Sức Khoẻ', 'Mưu Lược', 'Chính Trị', 'Thống Soái', 'Biện Tài']),
      z.object({
        "Chỉ Số": z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0)
      })
    ).prefault({}),
    "Công Tích": z.record(z.string(), z.string()).transform(data => {
      return _(data).entries().takeRight(10).fromPairs().value();
    }).prefault({}),
    "Tôn Xưng": z.record(z.string(), z.string()).prefault({})
  }).prefault({}),

  "Thế Lực Và Quân Sự": z.object({
    "Thế Lực": z.object({
      "Tình Trạng": z.enum(['Chấp Chưởng Thế Lực', 'Y Phụ Thế Lực', 'Tự Lập Sơn Đầu', 'Tạm Không']).prefault('Tạm Không'),
      "Tên": z.string().prefault('Không'),
      "Thủ Lĩnh": z.string().prefault('Không'),
      "Động Thái": z.string().prefault('Không')
    }).prefault({}),
    "Quân Đội": z.record(z.string(), z.object({
      "Tướng Lĩnh": z.string(),
      "Trú Địa": z.string(),
      "Số Lượng": z.coerce.number(),
      "Sĩ Khí": z.enum(['Thấp Kém', 'Mệt Mỏi', 'Bình Ổn', 'Phấn Chấn', 'Sục Sôi']),
      "Huấn Luyện": z.enum(['Bỏ Bê Thao Luyện', 'Sơ Thành Đội Ngũ', 'Tiến Thoái Có Độ', 'Hiệu Lệnh Nghiêm Minh', 'Tập Chiến Tinh Thục']),
      "Trang Bị": z.enum(['Sơ Sài', 'Thô Sơ', 'Chỉnh Tề', 'Tinh Lương', 'Sắc Bén']),
      "Trạng Thái Tiếp Tế": z.enum(['Tiếp Tế Đầy Đủ', 'Tiếp Tế Cảnh Báo', 'Thiếu Lương']),
      "Trạng Thái Trung Thành": z.enum(['Trung Thành', 'Tận Chức', 'Dao Động', 'Phản Loạn']),
      "Đánh Giá": z.string().describe('Đánh giá của bên ngoài hoặc chủ tướng đối với quân đội này'),
      "Động Thái": z.string()
    })).prefault({}),
    "Thuộc Hạ": z.record(z.string(), z.object({
      "Quan Chức": z.string(),
      "Quan Hệ": z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      "Đánh Giá": z.string()
    })).prefault({})
  }).prefault({}),

  "Tài Sản Và Quan Hệ": z.object({
    "Sản Nghiệp": z.record(z.string(), z.object({
      "Thu Nhập": z.coerce.number().prefault(0),
      "Chi Tiêu": z.coerce.number().prefault(0),
      "Đơn Vị": z.enum(['Thạch', 'Vàng']).prefault('Thạch')
    })).prefault({}),
    "Dự Trữ": z.object({
      "Lương Thực_Thạch": z.coerce.number().prefault(0),
      "Tiền_Vàng": z.coerce.number().prefault(0)
    }).prefault({}),
    "Tông Tộc": z.object({
      "Tên": z.string().prefault('Không'),
      "Thủ Lĩnh": z.string().prefault('Không'),
      "Cấp Bậc": z.string().prefault('Không'),
      "Động Thái": z.string().prefault('Không'),
      "Thành Viên": z.record(z.string(), z.object({
        "Quan Chức": z.string(),
        "Quan Hệ": z.coerce.number().transform(v => _.clamp(v, -100, 100)),
        "Đánh Giá": z.string()
      })).prefault({})
    }).prefault({}),
    "Mối Quan Hệ": z.record(z.string(), z.object({
      "Mô Tả Quan Hệ": z.string(),
      "Đánh Giá": z.string()
    })).prefault({})
  }).prefault({}),

  "Hậu Cung Và Tử Tức": z.object({
    "Động Thái Hậu Cung": z.string().prefault('Tạm Không'),
    "Hậu Cung": z.record(z.string(), z.object({
      "Quan Hệ": z.string(),
      "Tuổi Tác": z.coerce.number(),
      "Ngoại Hình": z.string(),
      "Đặc Tính": z.string(),
      "Hảo Cảm": z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      "Sủng Ái": z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      "Số Lần Ân Ái": z.object({
        "Miệng": z.coerce.number().prefault(0),
        "Tay": z.coerce.number().prefault(0),
        "Chân": z.coerce.number().prefault(0),
        "Ngực": z.coerce.number().prefault(0),
        "Âm Đạo": z.coerce.number().prefault(0),
        "Hậu Môn": z.coerce.number().prefault(0)
      }).prefault({})
    })).prefault({}),
    "Động Thái Tử Tự": z.string().prefault('Tạm Không'),
    "Tử Tự": z.record(z.string(), z.object({
      "Quan Hệ": z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      "Đánh Giá": z.string()
    })).prefault({})
  }).prefault({})
});

$(() => {
  registerMvuSchema(Schema);
})

