function generateAndGoToCrisis() {
    let crisesList = [];
    let rulesTarget; || 'Tân Học';
        if(userData.founderType === 'Lập Riêng') school = 'Tân Học';

        let schoolCrisis = worldData.crisisRules.allSchools[school];
        if(schoolCrisis && schoolCrisis['Cự Tử']) {
             generatedCrises = [...schoolCrisis['Cự Tử'].general];
        } else {
             generatedCrises = ['Học phái mới lập, bị các hiển học khác liên thủ giảo sát và bài xích.', 'Đệ tử môn hạ tốt xấu lẫn lộn, có kẻ mượn danh hiệu học phái ra ngoài gây chuyện thị phi.', 'Chư hầu đầy cảnh giác với học thuyết mới, hạ lệnh trục xuất môn đồ học phái.'];
        }

        if (userData.founderType === 'Phân Liệt') {
            generatedCrises.push('Học phái nguồn cội coi bạn là kẻ phản bội, phái thích khách đến thanh lý môn hộ.');
        } else if (userData.founderType === 'Kế Thừa') {
            generatedCrises.push('Nội bộ học phái vẫn có kẻ không phục, âm thầm mưu đồ tước đoạt ngôi vị thủ lĩnh.');
        }

    } else {
        if (userData.factionType === 'Bách Gia' && userData.path === 'Nhập Sĩ') {
            rulesTarget = worldData.crisisRules.allStates[userData.serveState];
            targetClass = 'Tân Hưng Quan Liêu (Sĩ)';
            targetFaction = userData.serveState;
        } else if (userData.factionType === 'Bách Gia' && (userData.path === 'Xuất Du' || userData.path === 'Luận Chiến')) {
            rulesTarget = worldData.crisisRules.allSchools[userData.faction];
        } else {
            rulesTarget = worldData.crisisRules.allStates[userData.faction];
        }

        var generatedCrises = [];

        if(worldData.crisisRules.crisis_year[year] && worldData.crisisRules.crisis_year[year][targetFaction] && worldData.crisisRules.crisis_year[year][targetFaction][targetClass]) {
            generatedCrises.push(worldData.crisisRules.crisis_year[year][targetFaction][targetClass]);
        }

        if (userData.factionType === 'Bách Gia' && userData.path === 'Luận Chiến') {
            generatedCrises.push('Luận chiến phùng bại: Trong lúc biện luận bị chính địch hoặc học giả phái khác bác bỏ, thanh danh quét rác.');
            generatedCrises.push('Tính mệnh chi ưu: Ngôn từ chọc giận quyền quý địa phương, đối mặt với rủi ro bị ám sát hoặc trục xuất.');
        }

        if (rulesTarget && rulesTarget[targetClass] && rulesTarget[targetClass].general) {
            for(let g of rulesTarget[targetClass].general) {
                if(generatedCrises.length < 3 && !generatedCrises.includes(g)) generatedCrises.push(g);
            }
        }
        if(generatedCrises.length < 2) {
            for(let f of worldData.crisisRules.fallback) {
                if(generatedCrises.length < 3 && !generatedCrises.includes(f)) generatedCrises.push(f);
            }
        }
    }

    generatedCrises.forEach(desc => {
        crisesList.push({name: desc, desc: ''});
    });
    crisesList.push({name: 'Tự Định Nghĩa', desc: 'Tự nhập khốn cảnh cụ thể đang đối mặt'});

    userData.selectedCrises = [];
    renderCards('crisis-cards', crisesList, 'crisis-cards', item => {
        if(item.name === 'Tự Định Nghĩa') {
            const customDetails = document.getElementById('crisis-custom-details');
            customDetails.style.display = 'flex';
            userData.selectedCrises = ['Tự Định Nghĩa'];
        } else {
            document.getElementById('crisis-custom-details').style.display = 'none';
            userData.selectedCrises = [item.name];
        }
    }, false);

    goToPage(12);
}

