function saveCrisis() {
    let finalCrisis = '';
    if (userData.selectedCrises && userData.selectedCrises.includes('Tự Định Nghĩa')) {
        const customInfo = document.getElementById('crisis-custom-info').value.trim();
        if (customInfo) {
            finalCrisis = customInfo;
        } else {
            alert('Vui lòng điền nội dung nguy cơ cụ thể');
            return;
        }
    } else if (userData.selectedCrises && userData.selectedCrises.length > 0) {
        finalCrisis = userData.selectedCrises[0];
    } else {
        alert('Vui lòng chọn một nguy cơ');
        return;
    }

    userData.crisis = finalCrisis;
    displaySummary();
    goToPage(13);
}

