        lines.push(`Thiên Phú Dị Bẩm: ${formatTalentToString(userData.talents)}`);

        if (userData.factionType === 'Bách Gia' && userData.path === 'Luận Chiến') {
            lines.push(`Giao Phong Luận Chiến: Về 【${userData.debateTopic}】 cùng 【${userData.debateOpponent}】 triển khai biện luận kịch liệt`);
        } else if (userData.path === 'Khai Tông Lập Phái') {
            lines.push(`Lực Lượng Học Phái: ${userData.force.power}`);
        } else {
            let forceText = 'Tạm chưa có ban bệ';
            if (userData.force.type && userData.force.type !== 'Tạm chưa có ban bệ' && userData.force.type !== 'Lập đàn luận chiến') {
                if (userData.force.type === 'Y phụ thế lực') {
                    forceText = `${userData.force.name} (Thủ Lĩnh: ${userData.force.leader})`;
                } else if (userData.force.type === 'Tự lập sơn đầu') {
                    forceText = `${userData.force.name || 'Chưa đặt tên'}${userData.force.power ? ` (Binh Lực: ${userData.force.power})` : ''}`;
                    if(userData.force.subordinates) lines.push(`Thuộc Hạ Cốt Lõi: ${userData.force.subordinates}`);
                }
            }
            lines.push(`Quy Thuộc Thế Lực: ${forceText}`);
        }

        lines.push(`Nguy Cơ Hiện Tại: ${userData.crisis}`);
    }

    if(userData.assets) {
        lines.push(`Tài Sản Ban Đầu: Sản Nghiệp(${userData.assets.name}), Thu Nhập(${userData.assets.income}), Chi Tiêu(${userData.assets.expense})${userData.assets.food?`, Lương Thực(${userData.assets.food})`:''}${userData.assets.gold?`, Tiền(${userData.assets.gold})`:''}`);
    }

    if (userData.family_info) {
        lines.push(`Tình Hình Gia Tộc: ${userData.family_info}`);
    }

    if (userData.mode !== 'play' && userData.children.has && userData.children.info) {
        lines.push(`Tử Tự Đã Có: ${userData.children.info}`);
    }

    if (userData.mode !== 'play' && userData.companion.has) {
        let compStr = [];
        if (userData.companion.name) compStr.push(`Họ Tên: ${userData.companion.name}`);
        if (userData.companion.age) compStr.push(`Tuổi Tác: ${userData.companion.age}`);
        if (userData.companion.relation) compStr.push(`Quan Hệ: ${userData.companion.relation}`);
        if (userData.companion.custom) compStr.push(`Đặc Tính Khác: ${userData.companion.custom}`);
        lines.push(`Giai Nhân Bầu Bạn: ${compStr.join(' | ')}`);
    }

    if(userData.relations) lines.push(`Mối Quan Hệ: ${userData.relations}`);
    if(userData.mode !== 'play' && userData.force && userData.force.dynamic) {
        lines.push(`${userData.path === 'Khai Tông Lập Phái' ? 'Động Thái Học Phái' : 'Động Thái Thế Lực/Luận Chiến'}: ${userData.force.dynamic}`);
    }
    if(userData.custom) lines.push(`Thiết Lập Khác: ${userData.custom}`);
    return lines.join('\n');
}

function formatUserDataAsMessage() {
    let lines = [];
    if(userData.mode === 'play') {
        lines.push('Cuộc đời thanh sắc khuyển mã của tôi đã thiết lập xong, vui lòng dựa vào thông tin dưới đây để triển khai suy diễn hưởng lạc:\n');
        lines.push('【Thân Phận Và Địa Vị】');
        lines.push(`Tôi là ${userData.name}${userData.zi ? ` (tự ${userData.zi})` : ''}${userData.age ? `, đương độ ${userData.age} tuổi` : ''}.`);
        lines.push(`Tôi đang ở ${userData.playRegion} của ${userData.playState}, là một ${userData.playClass} tôn quý.`);

        if(userData.assets) {
            lines.push(`Tài sản của tôi rất phong phú——Sản Nghiệp: ${userData.assets.name}, Thu Nhập: ${userData.assets.income}, Chi Tiêu: ${userData.assets.expense}${userData.assets.food?`, Lương Thực: ${userData.assets.food}`:''}${userData.assets.gold?`, Tiền: ${userData.assets.gold}`:''}.`);
        }

        lines.push('\n【Tuế Nguyệt Phong Lưu】');
        lines.push(`Tôi say đắm trong: ${userData.playActs.join(', ')}.`);

        if(userData.playActs.includes('Ca Vũ') || userData.playActs.includes('Nữ Lư')) {
            lines.push(`Giai nhân hầu hạ bên cạnh tôi là: ${userData.playBeauty || 'Chưa chọn'}.`);
        }
    } else {
        lines.push('Thông tin nhân vật của tôi đã xác định, vui lòng dựa vào thiết lập dưới đây để bắt đầu suy diễn loạn thế Chiến Quốc:\n');
        lines.push('【Thân Phận Cơ Sở】');
        lines.push(`Cột Mốc Thời Gian: Năm ${userData.situation.year} - ${userData.situation.title}`);
        lines.push(`Uy Tín Chu Thất hiện tại là: ${userData.situation.zhou_prestige} (${userData.situation.zhou_desc}).`);
        lines.push(`Tôi là ${userData.name}${userData.zi ? ` (tự ${userData.zi})` : ''}${userData.age ? `, năm nay ${userData.age} tuổi` : ''}, đang ở ${userData.region}.`);

        if (userData.path === 'Khai Tông Lập Phái') {
            lines.push(`Tôi lấy hình thức 【${userData.founderType}】, lập phái là 【${userData.force.name}】.`);
            lines.push(`Chủ Chỉ: ${userData.founderDoctrine}`);
            lines.push(`Uyên Ương: ${userData.founderDesc}`);
            if(userData.founderRelation) lines.push(`Quan Hệ Học Phái: ${userData.founderRelation}`);
        } else {
            let pathStr = userData.factionType === 'Bách Gia' ? `chọn ${userData.path}, ` : '';
            let stateStr = (userData.factionType === 'Bách Gia' && userData.path === 'Nhập Sĩ') ? `hiệu lực cho ${userData.serveState}, ` : '';
            let compStr = (userData.factionType === 'Bách Gia' && (userData.path === 'Xuất Du' || userData.path === 'Luận Chiến')) ? `đồng hành cùng ${userData.travelCompanion}, ` : '';
            lines.push(`Xuất thân là ${userData.class} của trận doanh ${userData.faction}, thân phận địa vị hiện tại là ${userData.position}. ${pathStr}${stateStr}${compStr}`);
        }

        if (userData.family_info) {
            lines.push(`Tình Hình Gia Tộc: ${userData.family_info}`);
        }
        lines.push(`Danh vọng ban đầu của tôi là "${userData.reputation}".`);
        lines.push(`Thiên phú của tôi là: ${formatTalentToString(userData.talents)}.`);

        if (userData.children.has && userData.children.info) {
            lines.push(`Tử Tự đã có của tôi là: ${userData.children.info}.`);
        }

        lines.push('\n【Thế Lực Và Hoàn Cảnh】');

        if (userData.factionType === 'Bách Gia' && userData.path === 'Luận Chiến') {
            lines.push(`Tôi không hề tổ chức hay y phụ thế lực quân sự nào, mà là lập đàn luận chiến.`);
            lines.push(`Tôi sẽ lấy nghị đề cốt lõi 【${userData.debateTopic}】, cùng đối thủ cường đại 【${userData.debateOpponent}】 triển khai giao phong tư tưởng kịch liệt!`);
        } else if (userData.path === 'Khai Tông Lập Phái') {
            lines.push(`Lực lượng học phái do tôi chấp chưởng: ${userData.force.power}.`);
        } else {
            let forceLine = 'Tôi hiện tại tạm chưa có ban bệ thế lực, kiết nhiên nhất thân.';
            if (userData.force.type && userData.force.type !== 'Tạm chưa có ban bệ' && userData.force.type !== 'Lập đàn luận chiến') {
                if (userData.force.type === 'Y phụ thế lực') {
                    forceLine = `Tôi hiện tại y phụ vào ${userData.force.name} (Thủ Lĩnh: ${userData.force.leader}).`;
                } else if (userData.force.type === 'Tự lập sơn đầu') {
                    forceLine = `Tôi tự mình kiến lập một phương thế lực: ${userData.force.name || 'Chưa đặt tên'}.`;
                    if(userData.force.power) lines.push(`Trong tay nắm giữ binh lực: ${userData.force.power}.`);
                    if(userData.force.subordinates) lines.push(`Thuộc Hạ cốt lõi có: ${userData.force.subordinates}.`);
                }
            }
            lines.push(forceLine);
        }

        lines.push(`Nguy Cơ Hiện Tại tôi đang đối mặt là: ${userData.crisis}.`);

        if(userData.assets) {
            lines.push(`Tài sản ban đầu của tôi là——Sản Nghiệp: ${userData.assets.name}, Thu Nhập: ${userData.assets.income}, Chi Tiêu: ${userData.assets.expense}${userData.assets.food?`, Lương Thực: ${userData.assets.food}`:''}${userData.assets.gold?`, Tiền: ${userData.assets.gold}`:''}.`);
        }

        if (userData.companion.has) {
            lines.push('\n【Giai Nhân Bầu Bạn】');
            const cName = userData.companion.name || 'một nữ tử';
            let compText = `Bên cạnh tôi có ${cName} bầu bạn, nàng đương độ ${userData.companion.age || 'phương hoa'}, cùng tôi coi như là ${userData.companion.relation || 'bèo nước gặp nhau'}.`;
            if(userData.companion.custom) compText += `Nàng còn ${userData.companion.custom}.`;
            lines.push(compText);
        }
    }

    if(userData.relations || (userData.mode !== 'play' && userData.force && userData.force.dynamic) || userData.custom) {
        lines.push('\n【Bổ Sung Khác】');
        if(userData.relations) lines.push(`Mối Quan Hệ: ${userData.relations}`);
        if(userData.mode !== 'play' && userData.force && userData.force.dynamic) lines.push(`${userData.path === 'Khai Tông Lập Phái' ? 'Động Thái Học Phái' : 'Động Thái Thế Lực/Luận Chiến'}：${userData.force.dynamic}`);
        if(userData.custom) lines.push(`Thiết Lập Đặc Thù: ${userData.custom}`);
    }

    if(userData.mode === 'play') {
        lines.push('\nKhông màng đại thế thiên hạ, chỉ cầu sung sướng hôm nay. Vui lòng miêu tả tình cảnh cụ thể mà tôi đang đắm chìm trong đó.');
    } else {
        lines.push('\nĐại tranh chi thế, không tiến ắt lùi. Vui lòng miêu tả tình cảnh và quyết trạch cụ thể mà tôi đang phải đối mặt mũi chịu sào lúc này.');
    }

    return lines.join('\n');
}

function displaySummary() {
    const summaryInfo = document.getElementById('summary-info');
    let html = '';

    if(userData.mode === 'play') {
        document.getElementById('force-dynamic-group').style.display = 'none';
        html += `<strong>Lộ Trình Nhân Sinh:</strong> Thanh Sắc Khuyển Mã<br>
        <strong>Họ Tên:</strong> ${userData.name} (${userData.zi||'Không'}) ${userData.age ? `Tuổi Tác: ${userData.age}` : ''}<br>
        <strong>Nơi Ở Hiện Tại:</strong> ${userData.playState} - ${userData.playRegion}<br>
        <strong>Thân Phận Giai Cấp:</strong> ${userData.playClass}<br>
        <strong>Tài Sản:</strong> Sản Nghiệp(${userData.assets.name}), Thu Nhập(${userData.assets.income}), Chi Tiêu(${userData.assets.expense})<br>
        <strong>Lối Chơi Hưởng Lạc:</strong> ${userData.playActs.join(', ')}<br>`;

        if(userData.playActs.includes('Ca Vũ') || userData.playActs.includes('Nữ Lư')) {
            html += `<strong>Giai Nhân Bầu Bạn:</strong> ${userData.playBeauty || 'Chưa chọn'}<br>`;
        }
    } else {
        document.getElementById('force-dynamic-group').style.display = 'block';
        if (userData.path === 'Khai Tông Lập Phái') {
            document.getElementById('force-dynamic-label').innerText = 'Động Thái Học Phái (Tùy chọn)';
        } else {
            document.getElementById('force-dynamic-label').innerText = 'Động Thái Thế Lực/Luận Chiến (Tùy chọn)';
        }

        let pathStr = userData.factionType === 'Bách Gia' ? `[${userData.path}] ` : '';
        let stateStr = (userData.factionType === 'Bách Gia' && userData.path === 'Nhập Sĩ') ? `Hiệu lực cho ${userData.serveState}` : '';
        let compStr = (userData.factionType === 'Bách Gia' && (userData.path === 'Xuất Du' || userData.path === 'Luận Chiến')) ? `Người Đồng Hành: ${userData.travelCompanion}` : '';

        html += `<strong>Kịch Bản:</strong> ${userData.situation.title}<br>
            <strong>Họ Tên:</strong> ${userData.name} (${userData.zi||'Không'}) ${userData.age ? `Tuổi Tác: ${userData.age}` : ''}<br>`;

        if(userData.path === 'Khai Tông Lập Phái') {
            html += `<strong>Khai Phái:</strong> ${userData.founderType} - ${userData.force.name}<br>`;
        } else {
            html += `<strong>Xuất Thân:</strong> ${userData.faction} - ${userData.class} <br>`;
        }

        html += `<strong>Thân Phận/Trạng Thái:</strong> ${userData.position} ${pathStr} ${stateStr} ${compStr}<br>
            <strong>Khu Vực/Uy Vọng:</strong> ${userData.region} / ${userData.reputation}<br>
            <strong>Thiên Tư:</strong> ${formatTalentToString(userData.talents)}<br>`;

        if (userData.factionType === 'Bách Gia' && userData.path === 'Luận Chiến') {
            html += `<strong>Đối Tượng Giao Phong:</strong> ${userData.debateOpponent}<br>
                     <strong>Nghị Đề Cốt Lõi:</strong> ${userData.debateTopic}<br>`;
        } else if (userData.path === 'Khai Tông Lập Phái') {
            html += `<strong>Lực Lượng Học Phái:</strong> ${userData.force.power}<br>`;
        } else {
            html += `<strong>Thế Lực:</strong> ${userData.force.type === 'Tạm chưa có ban bệ' ? 'Không' : userData.force.name}<br>`;
        }

        html += `<strong>Nguy Cơ:</strong> ${userData.crisis}<br>`;

        if(userData.assets) {
            html += `<strong>Tài Sản:</strong> Sản Nghiệp(${userData.assets.name}), Thu Nhập(${userData.assets.income}), Chi Tiêu(${userData.assets.expense})<br>`;
        }

        if(userData.companion.has) html += `<strong>Giai Nhân:</strong> ${userData.companion.name||'Vô danh'} (${userData.companion.relation} - ${userData.companion.age})<br>`;
        if(userData.children.has) html += `<strong>Tử Tự:</strong> ${userData.children.info}<br>`;
    }

    summaryInfo.innerHTML = html;
    document.getElementById('summary-inputs').style.display = 'flex';
}

function openGlobalEditModal() {
    const body = document.getElementById('global-edit-body');
    body.innerHTML = '';

    const createInput = (label, id, val) => {
        return `<div class="edit-form-group">
            <label class="edit-form-label">${label}</label>
            <input class="input-field" style="text-align:left;" id="edit-${id}" value="${val || ''}">
        </div>`;
    };

    const createTextarea = (label, id, val) => {
        return `<div class="edit-form-group">
            <label class="edit-form-label">${label}</label>
            <textarea class="textarea-field" id="edit-${id}" style="min-height:60px;">${val || ''}</textarea>
        </div>`;
    };

    let html = '';
    html += createInput('Họ Tên', 'name', userData.name);
    html += createInput('Tuổi Tác', 'age', userData.age);
    html += createInput('Khu Vực', 'region', userData.region);
    html += createInput('Giai Cấp/Thân Phận', 'class', userData.class);

    if(userData.mode !== 'play') {
        html += createInput('Danh Vọng', 'reputation', userData.reputation);
        html += createTextarea('Nguy Cơ Hiện Tại', 'crisis', userData.crisis);
        if(userData.force) {
            html += createInput(userData.path === 'Khai Tông Lập Phái' ? 'Tên Học Phái' : 'Tên Thế Lực', 'force-name', userData.force.name);
            html += createInput(userData.path === 'Khai Tông Lập Phái' ? 'Lực Lượng Học Phái' : 'Binh Lực Thế Lực', 'force-power', userData.force.power);
        }
    }

    if(userData.assets) {
        html += createInput('Tài Sản-Sản Nghiệp', 'asset-name', userData.assets.name);
        html += createInput('Tài Sản-Thu Nhập', 'asset-in', userData.assets.income);
        html += createInput('Tài Sản-Chi Tiêu', 'asset-out', userData.assets.expense);
    }

    body.innerHTML = html;
    document.getElementById('global-edit-modal').classList.add('show');
}

function closeGlobalEditModal() {
    document.getElementById('global-edit-modal').classList.remove('show');
}

function saveGlobalEdit() {
    userData.name = document.getElementById('edit-name').value;
    userData.age = document.getElementById('edit-age').value;
    userData.region = document.getElementById('edit-region').value;
    userData.class = document.getElementById('edit-class').value;

    if(userData.mode !== 'play') {
        userData.reputation = document.getElementById('edit-reputation').value;
        userData.crisis = document.getElementById('edit-crisis').value;
        if(userData.force) {
            userData.force.name = document.getElementById('edit-force-name').value;
            userData.force.power = document.getElementById('edit-force-power').value;
        }
    }

    if(userData.assets) {
        userData.assets.name = document.getElementById('edit-asset-name').value;
        userData.assets.income = document.getElementById('edit-asset-in').value;
        userData.assets.expense = document.getElementById('edit-asset-out').value;
    }

    closeGlobalEditModal();
    displaySummary();
}

function showPreviewModal() {
    userData.family_info = document.getElementById('input-family-info').value;
    userData.relations = document.getElementById('input-relations').value;
    if(userData.mode !== 'play' && userData.force) userData.force.dynamic = document.getElementById('input-force-dynamic').value;
    userData.custom = document.getElementById('input-custom').value;

    const modal = document.getElementById('preview-modal');
    const textarea = document.getElementById('preview-textarea');
    const copyBtn = document.getElementById('btn-copy');

    textarea.value = formatUserDataAsMessage();

    copyBtn.innerText = 'Sao chép thông tin';
    copyBtn.style.borderColor = 'var(--main-color)';
    copyBtn.style.color = 'var(--main-color)';

    modal.classList.add('show');
}

function closePreviewModal() {
    document.getElementById('preview-modal').classList.remove('show');
}

function copyPreviewText() {
    const textarea = document.getElementById('preview-textarea');
    const copyBtn = document.getElementById('btn-copy');

    textarea.select();
    textarea.setSelectionRange(0, 99999);

    try {
        navigator.clipboard.writeText(textarea.value).then(() => {
            copyBtn.innerText = 'Sao chép thành công！';
            copyBtn.style.borderColor = 'var(--text-secondary)';
            copyBtn.style.color = 'var(--text-secondary)';
        }).catch(err => {
            document.execCommand('copy');
            copyBtn.innerText = 'Sao chép thành công！';
        });
    } catch (err) {
        document.execCommand('copy');
        copyBtn.innerText = 'Sao chép thành công！';
    }
}

function onConfirm() {
    userData.family_info = document.getElementById('input-family-info').value;
    userData.relations = document.getElementById('input-relations').value;
    if(userData.mode !== 'play' && userData.force) userData.force.dynamic = document.getElementById('input-force-dynamic').value;
    userData.custom = document.getElementById('input-custom').value;

    try {
        const charWB = getCharWorldbookNames('current');
        const wbName = charWB.primary;
        if (!wbName) {
            alert('Thẻ nhân vật hiện tại chưa liên kết với thế giới thư chính, không thể ghi mục thông tin người dùng.\nVui lòng liên kết một thế giới thư cho thẻ nhân vật trước.');
            return;
        }
        deleteWorldbookEntries(wbName, (entry) => entry.name === 'Thông tin người dùng').then(() => {
            return createWorldbookEntries(wbName, [{
                name: 'Thông tin người dùng',
                enabled: true,
                strategy: { type: 'constant' },
                position: { type: 'before_character_definition' },
                content: formatUserDataAsContent(),
            }]);
        }).then(() => {
            return createChatMessages([{ role: 'user', message: formatUserDataAsMessage() }]);
        }).then(() => {
            return triggerSlash('/send');
        }).catch((err) => {
            alert('Thao tác thất bại: ' + (err.message || String(err)));
            console.error('[Tạo Nhân Vật] onConfirm error:', err);
        });
    } catch(e) {
        console.log('Final User Data:', formatUserDataAsMessage());
        alert('Gọi API thất bại, vui lòng xác nhận đang chạy trong môi trường chính xác.\n' + e.message + '\n\nThiết lập nhân vật đã được xuất ra console.');
    }
}

document.addEventListener('DOMContentLoaded', () => { updateStepIndicator(); });
</script>
